  const reorderRule = (targetId: string) => { if (!draggedRuleId || draggedRuleId === targetId) return; setRules((current) => { const from = current.findIndex((rule) => rule.id === draggedRuleId); const to = current.findIndex((rule) => rule.id === targetId); if (from < 0 || to < 0) return current; const next = [...current]; const [moved] = next.splice(from, 1); next.splice(to, 0, moved); return next; }); setDraggedRuleId(null); };
  const beginPlaylistDrag = (event: React.PointerEvent, playlist: SpotifyPlaylistSummary, index: number, collection = visible) => { if (event.button !== 0) return; event.preventDefault(); if (event.shiftKey && lastIndex !== null) { const from = Math.min(lastIndex, index); const to = Math.max(lastIndex, index); setSelected((current) => Array.from(new Set(current.concat(collection.slice(from, to + 1).map((item) => item.id))))); setDragSelectMode("add"); } else { const mode = selected.includes(playlist.id) ? "remove" : "add"; setSelected((current) => mode === "add" ? Array.from(new Set(current.concat(playlist.id))) : current.filter((id) => id !== playlist.id)); setDragSelectMode(mode); } setLastIndex(index); };
