    if (demo) { const saved: PlaylistAutomationConfig = { id: draft.id || "demo-config-" + crypto.randomUUID(), name: draft.name.trim(), target_playlist_id: draft.target, source_playlist_ids: draft.sources, include_liked_songs: draft.includeLiked, exclude_liked_songs: draft.excludeLiked, exclude_keywords: draft.keywords.split(",").map((item) => item.trim()).filter(Boolean), sample_per_source: draft.sample ? Number(draft.sample) : null, update_mode: draft.mode, sort_enabled: draft.sort, sort_rules: rules, deduplicate: draft.dupes, dupe_preference: draft.dupePreference, version_replacer: draft.versions, version_preference: draft.versionPreference, automatic_group: draft.automaticGroup.trim(), preserve_local_files: draft.preserveLocalFiles }; setConfigs((current) => draft.id ? current.map((item) => item.id === saved.id ? saved : item) : [saved, ...current]); appendDebug("Info", "Saved dynamic playlist: " + saved.name); setModal(null); setMessage(saved.name + " saved in the local demo."); return; }
